  // (lshr A, C) + (zext (icmp ne (and A, (1 << C) - 1), 0)) => lshr (add A, (1 << C) - 1), C
  const APInt *C;
  CmpPredicate PredLocal;
  Value *Lshr;
  Value *Zext;
  if (match(&I, m_c_Add(m_Value(Lshr), m_Value(Zext))) &&
      match(Lshr, m_LShr(m_Value(A), m_APInt(C))) &&
      match(Zext, m_ZExt(m_ICmp(PredLocal,
                                m_And(m_Specific(A), m_Value(B)),
                                m_ZeroInt()))) &&
      PredLocal == ICmpInst::ICMP_NE &&
      match(B, m_SpecificInt((APInt(C->getBitWidth(), 1) << *C) - 1)) &&
      (Lshr->hasOneUse() && Zext->hasOneUse())) {
    if (willNotOverflowUnsignedAdd(A, B, I)) {
      Value *Add = Builder.CreateAdd(A, B, "", true, false); // hasNUW=true
      Value *NewLShr = Builder.CreateLShr(Add, ConstantInt::get(I.getType(), *C));
      return replaceInstUsesWith(I, NewLShr);
    }
  }

CODEEOF

